import{c as o,S as a,j as t,m as r}from"./chunks/framework.Bcm8lc2D.js";const u=JSON.parse('{"title":"AI 每日日报","description":"自动订阅 AI Hot 每日日报 feed","frontmatter":{"title":"AI 每日日报","description":"自动订阅 AI Hot 每日日报 feed"},"headers":[],"relativePath":"daily.md","filePath":"daily.md"}'),d={name:"daily.md"};function i(l,e,c,h,n,s){return a(),t("div",null,e[0]||(e[0]=[r('<h1 id="ai-每日日报" tabindex="-1">AI 每日日报 <a class="header-anchor" href="#ai-每日日报" aria-label="Permalink to &quot;AI 每日日报&quot;">​</a></h1><blockquote><p>数据来源：<a href="https://aihot.virxact.com/feed" target="_blank" rel="noreferrer">AI Hot 每日日报</a>，最近更新：2026-05-27 05:44:58 +0000</p></blockquote><h2 id="我国将加快研究推进人工智能健康发展综合性立法、低空经济立法等" tabindex="-1"><a href="https://www.ithome.com/0/955/758.htm" target="_blank" rel="noreferrer">我国将加快研究推进人工智能健康发展综合性立法、低空经济立法等</a> <a class="header-anchor" href="#我国将加快研究推进人工智能健康发展综合性立法、低空经济立法等" aria-label="Permalink to &quot;[我国将加快研究推进人工智能健康发展综合性立法、低空经济立法等](https://www.ithome.com/0/955/758.htm)&quot;">​</a></h2><p><code>Wed, 27 May 2026 02:54:29 GMT</code></p><h2 id="阿里云成为pytorch基金会白金会员" tabindex="-1"><a href="https://x.com/alibaba_cloud/status/2059453607075004835" target="_blank" rel="noreferrer">阿里云成为PyTorch基金会白金会员</a> <a class="header-anchor" href="#阿里云成为pytorch基金会白金会员" aria-label="Permalink to &quot;[阿里云成为PyTorch基金会白金会员](https://x.com/alibaba_cloud/status/2059453607075004835)&quot;">​</a></h2><p><code>Wed, 27 May 2026 01:56:17 GMT</code></p><p>阿里云宣布以白金会员身份加入PyTorch基金会。作为AI基础设施全球领导者，阿里云是开源模型家族Qwen的缔造方，已在多样化硬件上大规模运行PyTorch，将为社区带来生产级工程经验。</p><h2 id="claude-code-v2-1-152-更新发布" tabindex="-1"><a href="https://github.com/anthropics/claude-code/releases/tag/v2.1.152" target="_blank" rel="noreferrer">Claude Code v2.1.152 更新发布</a> <a class="header-anchor" href="#claude-code-v2-1-152-更新发布" aria-label="Permalink to &quot;[Claude Code v2.1.152 更新发布](https://github.com/anthropics/claude-code/releases/tag/v2.1.152)&quot;">​</a></h2><p><code>Wed, 27 May 2026 01:30:59 GMT</code></p><p>Claude Code 发布 v2.1.152 版本更新。核心改进包括：<code>/code-review --fix</code> 现在会将审查建议直接应用于工作目录；技能与斜杠命令支持通过 frontmatter 的 <code>disallowed-tools</code> 移除模型工具；新增 <code>/reload-skills</code> 命令可不重启会话重新扫描技能目录；<code>SessionStart</code> 钩子现可返回 <code>reloadSkills： true</code> 重新扫描技能，并可通过 <code>hookSpecificOutput.sessionTitle</code> 设置会话标题；</p><h2 id="消息称高通与字节跳动达成-ai-asic-芯片合作-采购量在数百万颗级别" tabindex="-1"><a href="https://www.ithome.com/0/955/674.htm" target="_blank" rel="noreferrer">消息称高通与字节跳动达成 AI ASIC 芯片合作，采购量在数百万颗级别</a> <a class="header-anchor" href="#消息称高通与字节跳动达成-ai-asic-芯片合作-采购量在数百万颗级别" aria-label="Permalink to &quot;[消息称高通与字节跳动达成 AI ASIC 芯片合作，采购量在数百万颗级别](https://www.ithome.com/0/955/674.htm)&quot;">​</a></h2><p><code>Wed, 27 May 2026 01:12:31 GMT</code></p><h2 id="code-w-claude-伦敦活动-重塑开发体验" tabindex="-1"><a href="https://claude.com/blog/code-w-claude-london-2026-rethinking-how-we-build" target="_blank" rel="noreferrer">Code w/ Claude 伦敦活动：重塑开发体验</a> <a class="header-anchor" href="#code-w-claude-伦敦活动-重塑开发体验" aria-label="Permalink to &quot;[Code w/ Claude 伦敦活动：重塑开发体验](https://claude.com/blog/code-w-claude-london-2026-rethinking-how-we-build)&quot;">​</a></h2><p><code>Wed, 27 May 2026 01:04:42 GMT</code></p><p>在Code w/ Claude 伦敦活动上，Anthropic 宣布了 Claude Managed Agents 的两项新能力：自托管沙箱（公开测试版）和 MCP 隧道（研究预览）。这两项功能使 AI 智能体的工具执行环境与企业私有网络内的 MCP 服务器连接均可运行在客户自有基础设施或指定托管服务商处。活动还介绍了如何通过 Claude Code、优化思维预算以及模型努力级别来提升开发体验。目前，包括 Spotify、Base44 和 Legora 在内的客户已在使用这些新功能。</p><h2 id="anthropic任命kiyoung-choi为韩国代表董事" tabindex="-1"><a href="https://www.anthropic.com/news/kiyoung-choi-representative-director-anthropic-korea" target="_blank" rel="noreferrer">Anthropic任命KiYoung Choi为韩国代表董事</a> <a class="header-anchor" href="#anthropic任命kiyoung-choi为韩国代表董事" aria-label="Permalink to &quot;[Anthropic任命KiYoung Choi为韩国代表董事](https://www.anthropic.com/news/kiyoung-choi-representative-director-anthropic-korea)&quot;">​</a></h2><p><code>Tue, 26 May 2026 23:34:41 GMT</code></p><p>Anthropic宣布任命KiYoung Choi为韩国代表董事，以支持其即将在首尔开设的办公室。根据Anthropic的经济指数，韩国是Claude.ai全球最活跃的市场之一，其使用率超过人口规模预期的3.5倍，主要用于技术和创意领域。KiYoung Choi此前曾担任Snowflake韩国区总经理，在Google Cloud、Adobe等公司拥有超过30年的科技行业领导经验。他将在韩国领导市场战略，支持本地企业和初创公司应用Claude，例如法律科技公司Law&amp;Company及韩国电信巨头SK Telecom均</p><h2 id="claude-code推出安全漏洞识别插件" tabindex="-1"><a href="https://x.com/ClaudeDevs/status/2059385239781384341" target="_blank" rel="noreferrer">Claude Code推出安全漏洞识别插件</a> <a class="header-anchor" href="#claude-code推出安全漏洞识别插件" aria-label="Permalink to &quot;[Claude Code推出安全漏洞识别插件](https://x.com/ClaudeDevs/status/2059385239781384341)&quot;">​</a></h2><p><code>Tue, 26 May 2026 21:24:37 GMT</code></p><p>我们为Claude Code发布了一个安全指导插件，可在编写代码时帮助识别和修复漏洞。 所有Claude Code用户均可使用。从插件市场（/plugins）安装。</p><h2 id="gemini-omni-视频提示词使用指南" tabindex="-1"><a href="https://x.com/GoogleAI/status/2059381218660270435" target="_blank" rel="noreferrer">Gemini Omni 视频提示词使用指南</a> <a class="header-anchor" href="#gemini-omni-视频提示词使用指南" aria-label="Permalink to &quot;[Gemini Omni 视频提示词使用指南](https://x.com/GoogleAI/status/2059381218660270435)&quot;">​</a></h2><p><code>Tue, 26 May 2026 21:08:38 GMT</code></p><p>Google 发布了其多模态模型 Gemini Omni 的视频生成功能使用指南。该模型可通过 Gemini 应用、Google Flow 等平台体验。指南包含五项提示词技巧：利用模型已有的现实世界知识进行简洁描述；精确控制文本在视频中的渲染与排版；使用专业镜头指令（如推拉摇移）像电影摄影师一样调度画面；通过迭代编辑高效修改视频；以及在生成中直接调整角色的动作节奏或情绪。其核心在于通过精准的提示词引导模型生成复杂且可控的视频内容。</p><h2 id="人类与ai分工-教育咨询及文学奖争议" tabindex="-1"><a href="https://x.com/emollick/status/2059363865536668040" target="_blank" rel="noreferrer">人类与AI分工：教育咨询及文学奖争议</a> <a class="header-anchor" href="#人类与ai分工-教育咨询及文学奖争议" aria-label="Permalink to &quot;[人类与AI分工：教育咨询及文学奖争议](https://x.com/emollick/status/2059363865536668040)&quot;">​</a></h2><p><code>Tue, 26 May 2026 19:59:41 GMT</code></p><p>我写了一篇新文章，探讨我们需要保留哪些人类特质，以及哪些可以交给AI，其中涉及教育、咨询领域的实验，以及最近关于文学奖的争议。</p><h2 id="选择保持人性" tabindex="-1"><a href="https://www.oneusefulthing.org/p/choosing-to-stay-human" target="_blank" rel="noreferrer">选择保持人性</a> <a class="header-anchor" href="#选择保持人性" aria-label="Permalink to &quot;[选择保持人性](https://www.oneusefulthing.org/p/choosing-to-stay-human)&quot;">​</a></h2><p><code>Tue, 26 May 2026 19:56:01 GMT</code></p><p>社交媒体平台上的帖子内容正变得越来越相似。这种趋同现象可能意味着大量内容正在被AI生成或同质化处理，引发了人们对于内容原创性与人类独特视角的讨论。</p><h2 id="mimo-2-5-pro大幅降价-与deepseek-v4-pro同价" tabindex="-1"><a href="https://x.com/kimmonismus/status/2059354372643975490" target="_blank" rel="noreferrer">MiMo 2.5 Pro大幅降价，与DeepSeek V4 Pro同价</a> <a class="header-anchor" href="#mimo-2-5-pro大幅降价-与deepseek-v4-pro同价" aria-label="Permalink to &quot;[MiMo 2.5 Pro大幅降价，与DeepSeek V4 Pro同价](https://x.com/kimmonismus/status/2059354372643975490)&quot;">​</a></h2><p><code>Tue, 26 May 2026 19:21:58 GMT</code></p><p>小米MiMo-V2.5系列API价格永久下调，最高降幅达99%，现与DeepSeek V4 Pro同价。Token套餐同步升级，同等价格下可用token量增加5-8倍，计费规则更简单透明。所有现有用户套餐额度将全额重置。此次降价源于MiMo全栈推理优化与服务效率提升，后续将发布技术博客详述细节。MiMo-V2.5-TTS限时免费，新定价于5月26日生效。</p><h2 id="据报道claude-mythos以-巧妙简洁的证明-解决了openai里程碑式的erdos问题" tabindex="-1"><a href="https://the-decoder.com/claude-mythos-reportedly-solves-openais-landmark-erdos-problem-with-a-cute-simple-proof" target="_blank" rel="noreferrer">据报道Claude Mythos以&quot;巧妙简洁的证明&quot;解决了OpenAI里程碑式的Erdős问题</a> <a class="header-anchor" href="#据报道claude-mythos以-巧妙简洁的证明-解决了openai里程碑式的erdos问题" aria-label="Permalink to &quot;[据报道Claude Mythos以&quot;巧妙简洁的证明&quot;解决了OpenAI里程碑式的Erdős问题](https://the-decoder.com/claude-mythos-reportedly-solves-openais-landmark-erdos-problem-with-a-cute-simple-proof)&quot;">​</a></h2><p><code>Tue, 26 May 2026 18:31:07 GMT</code></p><p>Anthropic工程师Sholto Douglas表示，Claude Mythos在周末期间解决了OpenAI提出的Erdős单位距离猜想问题，并给出了一个&quot;巧妙简洁的证明&quot;。这一成果被描述为人工智能在数学发现领域存在&quot;严重超前&quot;迹象。</p>',36)]))}const m=o(d,[["render",i]]);export{u as __pageData,m as default};
